select.if:
select distinct dr.id as registrationId, p.name as patientName, p.medical_record_no as medicalRecordNo from dms_registration dr inner join pms_patient p on dr.patient_id = p.id inner join dms_medicine_prescription_record pr on pr.registration_id = dr.id inner join dms_medicine_item_record mi on mi.prescription_id = pr.id where dr.bind_status = 1 and (pr.status is null or pr.status <> 2) and (pr.refund_status is null or pr.refund_status = 0) and (mi.status is null or mi.status <> 2) and COALESCE(mi.current_num, 0) > 0
and (p.name like concat('%', #{keyword}, '%') or p.medical_record_no like concat('%', #{keyword}, '%'))
order by dr.id desc limit #{limit}

select distinct dr.id as registrationId, p.name as patientName, p.medical_record_no as medicalRecordNo from dms_registration dr inner join pms_patient p on dr.patient_id = p.id where dr.bind_status = 1 and exists ( select 1 from dms_medicine_prescription_record pr where pr.registration_id = dr.id and (pr.status is null or pr.status <> 2) and (pr.refund_status is null or pr.refund_status = 0) ) and not exists ( select 1 from dms_medicine_item_record mi inner join dms_medicine_prescription_record pr2 on mi.prescription_id = pr2.id where pr2.registration_id = dr.id and (mi.status is null or mi.status <> 2) and COALESCE(mi.current_num, 0) > 0 )
and (p.name like concat('%', #{keyword}, '%') or p.medical_record_no like concat('%', #{keyword}, '%'))
order by dr.id desc limit #{limit}
